/* Return the largest sum of any contiguous subarray in the vector x.
   Uses Kadane's algorithm (O(n)) instead of the O(n²) brute force.
*/
int maximumSubarray(std::vector<int> const& x)
{
    if (x.empty())
        return std::numeric_limits<int>::lowest(); // matches original behaviour

    int max_ending_here = x[0];
    int global_max      = x[0];

    // Avoid branch mispredictions by using a single arithmetic update
    for (std::size_t i = 1; i < x.size(); ++i) {
        // Equivalent to: max_ending_here = std::max(x[i], max_ending_here + x[i]);
        max_ending_here = (max_ending_here < 0) ? x[i] : max_ending_here + x[i];
        global_max      = (max_ending_here > global_max) ? max_ending_here : global_max;
    }

    return global_max;
}
