 * This implementation is thread‑safe for the supplied harness and exploits
 * SIMD and parallelism as aggressively as possible under the target
 * compiler/architecture constraints (gcc -O2 -fopenmp, x86‑64, 8 cores).
 */
inline void relu(std::vector<double> &x) {
    const std::size_t n = x.size();

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        // Using a branchless form to keep the pipeline happy:
        // y = (x >= 0) * x
        const double v = x[i];
        x[i] = v * (v >= 0.0);
    }
