/* Compute the prefix sum array of the vector x and return its sum.
   The original code first builds an inclusive prefix sum array
   and then accumulates it.   Using the identity

        sum_i ( sum_{j<=i} x_j )  =  sum_j x_j * (n-j)

   we can compute the result in a single pass without
   allocating the intermediate array.  The parallel version
   distributes the work over the available threads and uses
   a reduction to accumulate the weighted sum.
*/
int64_t sumOfPrefixSum(const std::vector<int64_t> &x)
{
    const std::size_t n = x.size();
    int64_t result = 0;

#pragma omp parallel for reduction(+:result) schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        result += x[i] * static_cast<int64_t>(n - i);
    }

    return result;
}
