/* Vector x contains values between 0 and 100, inclusive. Count the number of
   values in [0,10), [10, 20), [20, 30), ... and store the counts in `bins`.
   Example:
   input: [7, 32, 95, 12, 39, 32, 11, 71, 70, 66]
   output: [1, 2, 0, 3, 0, 0, 1, 2, 0, 1]
*/
inline void binsBy10Count(std::vector<double> const& x, std::array<size_t, 10> &bins)
{
    // Ensure destination is zeroed
    std::fill(std::begin(bins), std::end(bins), static_cast<size_t>(0));

    const std::size_t n = x.size();

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        // clamp to [0,99] to avoid overflow when value is exactly 100
        // Safe because the spec says values are between 0 and 100 inclusive
        const double v = std::min(99.9999999999, std::max(0.0, x[i]));
        const std::size_t bin = static_cast<std::size_t>(v / 10.0);
        #pragma omp atomic
        bins[bin] += 1;
    }
}
