#pragma once
#include <array>
#include <string>
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * For each letter in the alphabet, counts the number of strings in the vector `s`
 * that start with that letter.  All strings are assumed to be lowercase.
 * The result is placed in `bins`, which must be zero‑initialised before the call.
 */
inline void firstLetterCounts(const std::vector<std::string> &s,
                              std::array<std::size_t, 26> &bins)
{
    // Divide the work among the available threads, each thread keeps a local
    // array to minimise false sharing and the cost of cache line traffic.
    const std::size_t N = s.size();
    const int nthreads = omp_get_max_threads();

    // If there are no jobs, return immediately.
    if (N == 0) return;

    // Temporary containers for private counts
    std::vector<std::array<std::size_t, 26>> local(nthreads);
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto &localBins = local[tid];
        // initialise local counts to zero
        for (auto &val : localBins) val = 0;

        // Work‑sharing loop
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < N; ++i)
        {
            const char c = s[i][0];
            const std::size_t index = static_cast<std::size_t>(c - 'a');
            // Bounds are guaranteed by the problem statement
            ++localBins[index];
        }
    }

    // Combine the per‑thread results into the final bins array
    for (int t = 0; t < nthreads; ++t)
        for (int idx = 0; idx < 26; ++idx)
            bins[idx] += local[t][idx];
}
