inline void reversePrefixSum(const std::vector<int> &x, std::vector<int> &output) {
    // Ensure output has the same size – matches original behaviour
    output.resize(x.size());

    int sum = 0;
    // Iterate from the end to the beginning
    for (int i = static_cast<int>(x.size()) - 1; i >= 0; --i) {
        sum += x[i];
        output[i] = sum;          // store in the original index position
    }
