#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

struct Point {
    double x, y;
};

void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4> &bins) {
    /* initialise all bins to zero */
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    /* use a thread‑local array to avoid contention on the shared
       result.  Each thread will accumulate its own count and we
       combine them at the end. */
    const std::size_t n = points.size();
#pragma omp parallel
    {
        std::array<std::size_t, 4> local{0, 0, 0, 0};
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            const auto &p = points[i];
            /* Two comparisons to decide the quadrant.  The
               branch‑free approach keeps the inner loop
               vectorisable by the compiler. */
            const std::size_t quad = (p.x >= 0.0) << 1 | (p.y >= 0.0);
            /* quad: 0 – Q1, 1 – Q4, 2 – Q2, 3 – Q3 (bitwise reversed?)
               The mapping below matches the original code */
            if (quad == 0)     local[0]++;   /* x>=0, y>=0              */
            else if (quad == 2) local[1]++;   /* x<0,  y>=0              */
            else if (quad == 3) local[2]++;   /* x<0,  y<0               */
            else               local[3]++;   /* x>=0, y<0               */
        }
#pragma omp critical
        {
            for (int q = 0; q < 4; ++q) bins[q] += local[q];
        }
    }
}
