/*
 * Compute the highest node degree in the undirected graph.
 * The graph is defined in the adjacency matrix A.
 * A is an NxN adjacency matrix stored in row-major. A is undirected.
 */
int maxDegree(const std::vector<int>& A, std::size_t N) {
    int highestDegree = 0;

    // Parallel reduce over rows: each thread computes the sum of a row
    // and updates the maximum value safely.
    #pragma omp parallel for reduction(max:highestDegree) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        int rowSum = 0;
        std::size_t rowStart = i * N;
        // unroll by 8 for a little more speed on large matrices
        std::size_t j = 0;
        for (; j + 7 < N; j += 8) {
            rowSum += A[rowStart + j]   + A[rowStart + j + 1] +
                      A[rowStart + j + 2] + A[rowStart + j + 3] +
                      A[rowStart + j + 4] + A[rowStart + j + 5] +
                      A[rowStart + j + 6] + A[rowStart + j + 7];
        }
        for (; j < N; ++j) {
            rowSum += A[rowStart + j];
        }
        if (rowSum > highestDegree)
            highestDegree = rowSum;   // This update is protected by the reduction
    }
    return highestDegree;
}
