struct Element {
    size_t index;
    double value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
 * z is assumed to be preallocated and initialized to zero by the caller.
 *
 * The implementation uses two parallel loops with atomic additions.
 * This preserves the exact result while exploiting all available CPUs.
 */
inline void sparseAxpy(double alpha,
                       std::vector<Element> const& x,
                       std::vector<Element> const& y,
                       std::vector<double> &z)
{
    // Safe parallel addition of contributions from x
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i)
    {
        size_t idx = x[i].index;
        double delta = alpha * x[i].value;
        #pragma omp atomic
        z[idx] += delta;
    }

    // Safe parallel addition of contributions from y
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i)
    {
        size_t idx = y[i].index;
        double delta = y[i].value;
        #pragma omp atomic
        z[idx] += delta;
    }
}
