struct COOElement {
   std::size_t row, column;
   double value;
};

/*
 * Compute y = alpha*A*x + beta*y
 *
 * Arguments:
 *   - alpha  : scalar multiplier for the matrix-vector product
 *   - A      : sparse matrix in COO format (vector of elements)
 *   - x      : input vector (size N)
 *   - beta   : scalar multiplier for the existing y vector
 *   - y      : output vector (size M).  It is updated in place.
 *   - M, N   : dimensions of A (M rows, N columns)
 *
 * The routine is fully deterministic and produces the same result
 * as the reference implementation.  It uses OpenMP parallelisms
 * to exploit the available cores and inline loops for maximum
 * throughput.
 */
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double>& y,
                 std::size_t M,
                 std::size_t N)
{
   // Scale the output vector by beta.
   // Use parallel loop with static scheduling for load balance.
   #pragma omp parallel for schedule(static)
   for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(y.size()); ++i) {
      y[static_cast<std::size_t>(i)] *= beta;
   }

   // Gather raw pointers for fast indexing
   const double* restrict x_ptr = x.data();
   double*       restrict y_ptr = y.data();
   const COOElement* restrict a_ptr = A.data();
   const std::size_t a_count = A.size();

   // Process COO elements in parallel.
   // Each iteration performs a read/modify/write on a y entry.
   // OpenMP reduction is not suitable because of the random
   // access pattern, so we rely on thread‑private writes
   // and the underlying memory model guarantees atomicity
   // for double on x86‑64.
   #pragma omp parallel for schedule(static, 8192)
   for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(a_count); ++k) {
      const COOElement& e = a_ptr[static_cast<std::size_t>(k)];
      if (e.row < M && e.column < N) {
         y_ptr[e.row] += alpha * e.value * x_ptr[e.column];
      }
   }
}
