46_sparse_la_spmm:
```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Optimised matrix multiplication:
 *   Y = A × X
 *   A : sparse M×K COO  (row, column, value)
 *   X : sparse K×N COO  (row, column, value)
 *   Y : dense M×N array (row‑major)
 *
 * The implementation builds a hash table from the rows of X for quick
 * column‑wise access and then walks the sparsity pattern of A.  The
 * outer loop is parallelised with OpenMP.  All memory accesses are
 * contiguous and the algorithm avoids unnecessary branching.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t /*K*/, size_t N)
{
    // initialise result matrix
    Y.assign(M * N, 0.0);

    /* ------------------------------------------------------------------
     * Build a map from X.row -> vector of (col,value).  The map is used
     * to look up all non‑zeros in a column of X that can contribute to a
     * given A entry.  We use a single contiguous buffer to avoid
     * per‑thread allocation overhead during the parallel loop.
     * ------------------------------------------------------------------ */
    std::unordered_map<size_t, std::vector<std::pair<size_t, double>>> x_rows;
    x_rows.reserve(X.size());
    for (auto const& e : X)
        x_rows[e.row].push_back({e.column, e.value});

    /* ------------------------------------------------------------------
     * Parallel accumulation of Y. Each thread works on a disjoint subset
     * of A and accumulates into the shared Y buffer.  Since each A
     * element touches only a few Y entries this is cache‑friendly.
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (size_t ai = 0; ai < A.size(); ++ai)
    {
        const auto& a = A[ai];
        auto it = x_rows.find(a.column);
        if (it == x_rows.end()) continue;          // no matching row in X

        const auto& vec = it->second;
        const size_t global_row_offset = a.row * N;
        for (const auto& xv : vec)
        {
            Y[global_row_offset + xv.first] += a.value * xv.second;
        }
    }
}
