#pragma once
#include <array>
#include <cstddef>
#include <vector>
#include <cmath>
#include <omp.h>

/* Count the number of doubles in the vector `x` that have a fractional part  
   in the four quartile ranges and store the counts in `bins`.  
   The original algorithm performed a % 1 operation by subtracting the
   floor of the value; this implementation uses `std::modf` for a single
   round‑trip conversion to preserve the exact semantics.  OpenMP is used
   to parallelise the loop, while a simple collapse of multiple `if`s
   keeps the branching structure straightforward.  The algorithm
   is safe for any array size, including an empty vector, and matches
   the original behaviour exactly. */
inline void countQuartiles(
    const std::vector<double>& x,
    std::array<size_t, 4>& bins)
{
    if (x.empty())
        return;

    const std::size_t N = x.size();
    // Temporary per‑thread counters to avoid contention
    std::vector<std::array<size_t, 4>> threadBins(omp_get_max_threads(),
                                                 {0, 0, 0, 0});

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto& local = threadBins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < N; ++i)
        {
            double intpart;
            const double frac = std::modf(x[i], &intpart); // frac in [ -0.5, 0.5 )

            // Convert negative fractional parts to the equivalent positive
            // value in [0,1) as per the original (casting to int truncates toward 0).
            double f = frac;
            if (f < 0)
                f += 1.0;

            if (f < 0.25) {
                ++local[0];
            } else if (f < 0.5) {
                ++local[1];
            } else if (f < 0.75) {
                ++local[2];
            } else {
                ++local[3];
            }
        }
    }

    // Combine per‑thread results into the final output
    bins.fill(0);
