/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
inline void pixelCounts(std::vector<int> const& image, std::array<std::size_t, 256> &bins)
{
    // Zero the output histogram
    bins.fill(0);

    const std::size_t n = image.size();
    if (n == 0) return;

    // Determine the number of threads to use
    int nthreads = omp_get_max_threads();

    // Allocate a per‑thread temporary histogram
    std::vector<std::array<std::size_t, 256>> local_histograms(nthreads);
    for (auto& h : local_histograms) h.fill(0);

    // Parallel scan the image in contiguous chunks
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::size_t chunk_size = (n + nthreads - 1) / nthreads;
        std::size_t start = std::size_t(tid) * chunk_size;
        std::size_t end   = std::min(start + chunk_size, n);

        // Each thread updates its own local histogram
        for (std::size_t i = start; i < end; ++i) {
            ++local_histograms[tid][static_cast<std::size_t>(image[i])];
        }
    }

    // Merge local histograms into the global result
    detail::mergeHistograms(bins, local_histograms.data(), nthreads);
}
