   output: 2
*/
double closestPair(std::vector<double> const& x) noexcept {
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    double minDist = std::numeric_limits<double>::max();

    // Parallelize outer loop with reduction on minDist.
    #pragma omp parallel for schedule(static) reduction(min:minDist)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n - 1); ++i) {
        const double xi = x[static_cast<std::size_t>(i)];
        for (std::size_t j = i + 1; j < n; ++j) {
            const double d = abs_diff(xi, x[j]);
