#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>

/*
 * Parallel inclusive prefix sum.
 * The algorithm is a two‑pass parallel scan:
 *   1. Each thread computes the sum of its chunk (local sums).
 *   2. A serial prefix of the local sums is computed to obtain
 *      the offset of each chunk relative to the whole array.
 *   3. Each thread adds its offset to every element in its chunk.
 *
 * The implementation is fully deterministic and preserves the exact
 * behavior of the sequential std::inclusive_scan.
 */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    const std::size_t N = x.size();
    output.resize(N);

    if (N == 0) return;

    const int maxThreads = omp_get_max_threads();
    int numThreads = (N < static_cast<std::size_t>(maxThreads)) ? static_cast<int>(N) : maxThreads;

    std::vector<int64_t> localSums(numThreads, 0);
    std::vector<std::size_t> chunkBegins(numThreads);

    /* Determine chunk boundaries */
    std::size_t blockSize = (N + numThreads - 1) / numThreads;
    for (int t = 0; t < numThreads; ++t) {
        chunkBegins[t] = t * blockSize;
    }

    /* First pass: compute local sums in parallel */
#pragma omp parallel num_threads(numThreads)
    {
        int t = omp_get_thread_num();
        std::size_t begin = chunkBegins[t];
        std::size_t end   = std::min(begin + blockSize, N);

        int64_t sum = 0;
        for (std::size_t i = begin; i < end; ++i) {
            sum += x[i];
            output[i] = sum;   // partial prefix inside the chunk
        }
        localSums[t] = sum;
    }

    /* Serial prefix of local sums to obtain chunk offsets */
    std::vector<int64_t> chunkOffsets(numThreads, 0);
    for (int t = 1; t < numThreads; ++t) {
        chunkOffsets[t] = chunkOffsets[t-1] + localSums[t-1];
    }

    /* Second pass: add offsets to each chunk (parallel) */
#pragma omp parallel num_threads(numThreads)
    {
        int t = omp_get_thread_num();
        std::size_t begin = chunkBegins[t];
        std::size_t end   = std::min(begin + blockSize, N);

        int64_t offset = chunkOffsets[t];
        for (std::size_t i = begin; i < end; ++i) {
            output[i] += offset;
        }
    }
}
