#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Factorize the sparse matrix A into A=LU where L is a lower triangular matrix and U is an upper triangular matrix.
   A is a sparse NxN matrix stored in COO format. L and U are NxN matrices in row-major.
   Example:
   input: A=[{0,0,4}, {0,1,3}, {1,0,6}, {1,1,3}]
   output: L=[{0,0,1},{1,0,1.5}, {1,1,1}] U=[{0,0,4}, {0,1,3}, {1,1,-1.5}]
*/
void luFactorize(std::vector<COOElement> const& A, std::vector<double> &L, std::vector<double> &U, size_t N) {
    /* ---- Build the dense matrix from the COO representation ---- */
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A) {
        fullA[e.row * N + e.column] = e.value;
    }

    /* Ensure L and U have the correct size and are zero‑initialized */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* ---- LU factorization, parallel over rows i ---- */
    #pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(N); ++i) {
        /* U part (j ≥ i) */
        for (size_t j = i; j < N; ++j) {
            double sum = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = sum;
        }

        /* L part (j < i) */
        for (size_t j = 0; j < i; ++j) {
            double sum = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            /* Diagonal of U is guaranteed non‑zero here */
            L[i * N + j] = sum / U[j * N + j];
        }

        /* Unit diagonal for L */
        L[i * N + i] = 1.0;
    }
}
