/* Compute one iteration of a 3‑point 1D Jacobi stencil on `input`.
 * Store the results in `output`. Each element of `input` is averaged
 * with its two neighbors (using 0 for out‑of‑bounds). The function
 * preserves the exact behaviour of the reference implementation.
 */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;               // nothing to do

    // Ensure output is of correct size (habit of the original code).
    if (output.size() != n) output.resize(n);

    // Pointers to the underlying data for faster random access
    const double *in  = input.data();
          double *out = output.data();

    const double inv3 = 1.0 / 3.0;

    // For the first element, left neighbour is zero:
    out[0] = (in[0] + in[1]) * inv3;

    // Parallel interior loop: no branch inside.
#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        out[i] = (in[i-1] + in[i] + in[i+1]) * inv3;
    }

    // For the last element, right neighbour is zero:
    if (n > 1)
        out[n-1] = (in[n-2] + in[n-1]) * inv3;
}
