#pragma once
#include <vector>
#include <limits>

/*
   Return the length of the shortest path from source to dest in the
   undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major order.
   The graph is guaranteed to be connected and undirected.
*/
inline int shortestPathLength(const std::vector<int>& A, size_t N,
                               int source, int dest) {
    // Use a bit‑packed visited array (char is 1 byte, good enough for flags).
    std::vector<char> visited(N, 0);

    // Simple circular queue implemented with a vector.
    std::vector<int> queue(N);
    std::vector<int> dist(N, -1);

    int head = 0, tail = 0;
    visited[source] = 1;
    dist[source]  = 0;
    queue[tail++] = source;

    while (head < tail) {
        int cur = queue[head++];
        int curDist = dist[cur];

        if (cur == dest)
            return curDist;

        // Pointer to the current row of the adjacency matrix
        const int* row = &A[cur * N];

        // Scan all potential neighbours
        for (size_t i = 0; i < N; ++i) {
            if (row[i] && !visited[i]) {
                visited[i] = 1;
                dist[i] = curDist + 1;
                queue[tail++] = static_cast<int>(i);
            }
        }
    }

    // Should never reach here as the graph is connected
    return std::numeric_limits<int>::max();
}
