#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* Compute the discrete Fourier transform of x and store the result in output.
 * Maintains identical numerical behaviour to the reference implementation.
 */
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output) {
    const int N = static_cast<int>(x.size());
    output.resize(N, std::complex<double>(0.0, 0.0));

#pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        // Precompute the twiddle factor w = exp(-j*2πk/N)
        const double theta = -2.0 * M_PI * static_cast<double>(k) / static_cast<double>(N);
        const double w_real = std::cos(theta);
        const double w_imag = std::sin(theta);

        // Start with c = 1 (the first twiddle factor)
        double c_real = 1.0, c_imag = 0.0;
        double sum_real = 0.0, sum_imag = 0.0;

        for (int n = 0; n < N; ++n) {
            // Accumulate the contribution of x[n] * c
            sum_real += x[n] * c_real;
            sum_imag += x[n] * c_imag;

            // Update c = c * w for the next n
            const double new_c_real = c_real * w_real - c_imag * w_imag;
            const double new_c_imag = c_real * w_imag + c_imag * w_real;
            c_real = new_c_real;
            c_imag = new_c_imag;
        }

        output[k] = std::complex<double>(sum_real, sum_imag);
    }
}
