/* Count the number of connected components in the undirected graph
   defined by the adjacency matrix A.                                                  */
int componentCount(std::vector<int> const& A, size_t N)
{
    /* Atomic visited array so that threads can safely claim
       a node as the root of a component.                                   */
    std::vector<std::atomic_uint8_t> visited(N);
    for (size_t i = 0; i < N; ++i) visited[i].store(0, std::memory_order_relaxed);

    int components = 0;

    /* Parallel outer loop.  Each thread attempts to start a new component
       from a node that hasn't been claimed yet.  The atomic test_and_set
       guarantees that only one thread claims each component root.       */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < (int)N; ++i) {
        /* Try to claim node i.  If the node was already visited, skip. */
        if (!visited[i].exchange(1, std::memory_order_acq_rel)) {
#pragma omp atomic
            components++;

            /* Iterative depth‑first search from the root node 'i'. */
            std::stack<int> st;
            st.push(i);

            while (!st.empty()) {
                int u = st.top(); st.pop();
                size_t base = u * N;
                for (size_t v = 0; v < N; ++v) {
                    if (A[base + v] == 1 && !visited[v].exchange(1, std::memory_order_acq_rel)) {
                        st.push((int)v);
                    }
                }
            }
        }
    }

    return components;
}
