/*
 * Replace the i‑th element of the vector `x` with the minimum value
 * from indices `0` through `i`.  The implementation below performs a
 * parallel prefix scan using a divide and conquer strategy that scales
 * to many threads while preserving the exact semantics of the
 * sequential algorithm.
 */
inline void partialMinimums(std::vector<float>& x)
{
    const std::size_t n = x.size();
    if (n <= 1)
        return;

    /* 1. Compute the local prefix minima for each chunk (per thread). */
    const std::size_t num_threads = std::min<std::size_t>(omp_get_max_threads(), n);
    std::vector<float> block_mins(num_threads);
    std::vector<std::size_t> block_starts(num_threads + 1, 0);

    const std::size_t block_size = (n + num_threads - 1) / num_threads;
    for (std::size_t t = 0; t < num_threads; ++t) {
        const std::size_t start = t * block_size;
        const std::size_t end   = std::min(start + block_size, n);
        block_starts[t] = start;
        if (start < end) {
            float current = std::numeric_limits<float>::max();
            for (std::size_t i = start; i < end; ++i) {
                current = std::min(current, x[i]);
                x[i] = current;
            }
            block_mins[t] = current;
        } else {
            block_mins[t] = std::numeric_limits<float>::max();
        }
    }
    block_starts[num_threads] = n;

    /* 2. Compute the prefix minimum of the block minima (sequential
     *    because the number of blocks is usually small). */
    std::vector<float> block_prefix(num_threads);
    float current = std::numeric_limits<float>::max();
    for (std::size_t t = 0; t < num_threads; ++t) {
        current = std::min(current, block_mins[t]);
        block_prefix[t] = current;
    }

    /* 3. Propagate the block prefix minima to the remaining elements
     *    in each block, except for the first element of each block
     *    which is already correct (it was computed locally). */
    #pragma omp parallel for schedule(static)
    for (std::size_t t = 0; t < num_threads; ++t) {
        const std::size_t start = block_starts[t];
        const std::size_t end   = block_starts[t + 1];
        if (start < end) {
            float prefix = block_prefix[t];
            for (std::size_t i = start; i < end; ++i) {
                /* The first element has already been set to the
                 * correct local minimum; only update if we need
                 * a smaller prefix from earlier blocks. */
                x[i] = std::min(prefix, x[i]);
            }
        }
    }
}
