/* Return the number of vertices in the largest component of the graph defined by
   the adjacency matrix A (stored in row‑major order).
*/
int largestComponent(std::vector<int> const& A, size_t N)
{
    // Use a compact visited array (byte per vertex).
    std::vector<char> visited(N, 0);
    int maxCount = 0;

    // Iterate over all possible starting vertices.
    for (size_t start = 0; start < N; ++start) {
        if (visited[start]) continue;

        // Iterative DFS using an explicit stack.
        std::stack<size_t> st;
        st.push(start);
        int count = 0;

        while (!st.empty()) {
            size_t v = st.top(); st.pop();
            if (visited[v]) continue;
            visited[v] = 1;
            ++count;

            // Scan the row of the adjacency matrix once.
            const int* row = A.data() + v * N;
            for (size_t w = 0; w < N; ++w) {
                if (row[w] == 1 && !visited[w]) {
                    st.push(w);
                }
            }
        }

        if (count > maxCount) maxCount = count;
    }

    return maxCount;
}
