#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

/*---------------------------------------------------------------
  Optimised in‑place radix‑2 Cooley‑Tukey FFT.
  The routine preserves the exact numerical output of the
  original serial reference implementation while exploiting
  loop parallelisation and fewer memory copies.
  Input :  x        – data to transform (size must be a power of 2)
  Output:  r, i      – real / imaginary parts of the result
 ---------------------------------------------------------------*/
void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r, std::vector<double> &i)
{
    const unsigned N = static_cast<unsigned>(x.size());
    if (N == 0) return;

    /*----- 1.  Bit‑reversal permutation ------------------------------------*/
    std::vector<std::complex<double>> a(x);          // copy input
    unsigned m = static_cast<unsigned>(std::log2(N));
    for (unsigned i = 0; i < N; ++i) {
        unsigned rev = ((i & 0x55555555u) << 1) | ((i & 0xaaaaaaaau) >> 1);
        rev = ((rev & 0x33333333u) << 2) | ((rev & 0xccccccccu) >> 2);
        rev = ((rev & 0x0f0f0f0fu) << 4) | ((rev & 0xf0f0f0f0u) >> 4);
        rev = ((rev & 0x00ff00ffu) << 8) | ((rev & 0xff00ff00u) >> 8);
        rev = (rev << 16) | (rev >> 16);
        rev >>= (32 - m);
        if (rev > i) std::swap(a[i], a[rev]);
    }

    /*----- 2.  Pre‑compute twiddle factors ---------------------------------*/
    std::vector<std::complex<double>> w(N/2);
    const double pi = std::acos(-1.0);
    for (unsigned k = 0; k < N/2; ++k)
        w[k] = std::exp(std::complex<double>(0, -2.0 * pi * k / N));

    /*----- 3.  Iterative decimation‑in‑time (iterative butterfly) --------*/
    unsigned step = 1;                     // size of sub‑FFT
    for (unsigned level = 0; level < m; ++level) {
        unsigned half = step;
        unsigned span  = step * 2;
        // parallelise over the outer loop – independent butterfly blocks
        #pragma omp parallel for schedule(static)
        for (unsigned i = 0; i < N; i += span) {
            for (unsigned j = 0; j < half; ++j) {
                std::complex<double> z = w[(j * N) / span] * a[i + j + half];
                std::complex<double> u = a[i + j];
                a[i + j]         = u + z;
                a[i + j + half]  = u - z;
            }
        }
        step = span;
    }

    /*----- 4.  Copy result to output vectors -----------------------------*/
    r.resize(N);
    i.resize(N);
    #pragma omp parallel for
    for (unsigned j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
