#include <omp.h>

struct COOElement {
   std::size_t row, column;
   double value;
};

/*
 * Solve Ax = b where A is an N×N sparse matrix in COO format.
 * The algorithm is exact Gauss‑Elimination with partial pivoting.
 */
inline void solveLinearSystem(std::vector<COOElement> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              std::size_t N)
{
   /* --- dense storage, row major, flat array for cache friendliness --- */
   std::vector<double> M(N * N, 0.0);
   std::vector<double> B(b.begin(), b.end());

   /* Populate matrix */
   for (auto const& e : A) {
      M[e.row * N + e.column] = e.value;
   }

   x.assign(N, 0.0);

   /* Forward elimination with partial pivoting */
   for (std::size_t i = 0; i < N; ++i) {
      /* Find pivot row (parallel reduction) */
      std::size_t pivotRow = i;
      double     pivotVal = std::abs(M[i * N + i]);

#pragma omp parallel
      {
         std::size_t localRow  = i;
         double      localMax  = pivotVal;

#pragma omp for reduction(max:localMax) schedule(static)
         for (std::size_t k = i + 1; k < N; ++k) {
            double const val = std::abs(M[k * N + i]);
            if (val > localMax) {
               localMax = val;
               localRow = k;
            }
         }

#pragma omp critical
         {
            if (localMax > pivotVal) {
               pivotVal = localMax;
               pivotRow = localRow;
            }
         }
      }

      /* Swap rows if necessary */
      if (pivotRow != i) {
         std::swap_ranges(M.begin() + i * N,
                          M.begin() + (i + 1) * N,
                          M.begin() + pivotRow * N);
         std::swap(B[i], B[pivotRow]);
      }

      double const dii = M[i * N + i];
      /* Zero under the pivot and update RHS */
#pragma omp parallel for schedule(static)
      for (std::size_t k = i + 1; k < N; ++k) {
         double const factor = -M[k * N + i] / dii;
         double       *rowK  = &M[k * N];
         double       *rowI  = &M[i * N];
         for (std::size_t j = i; j < N; ++j) {
            if (i == j) {
               rowK[j] = 0.0;        // explicit zeroing for clarity
            } else {
               rowK[j] += factor * rowI[j];
            }
         }
         B[k] += factor * B[i];
      }
   }

   /* Back substitution */
   for (int64_t i = static_cast<int64_t>(N) - 1; i >= 0; --i) {
      x[i] = B[i] / M[i * N + i];
      double const xi = x[i];
#pragma omp parallel for schedule(static)
      for (int64_t k = i - 1; k >= 0; --k) {
         B[k] -= M[k * N + i] * xi;
      }
   }
}
