/* Set every cell's value to 1 if it has exactly one neighbour that's a 1.
   The algorithm scans a square N×N grid. Using OpenMP to parallelise
   the outer loop gives a high speed‑up on a multi‑core machine while
   keeping the logic identical to the original implementation.  */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     std::size_t N)
{
    // Guard against empty runs; guarantees output has same size as input
    if (N == 0) return;

    const int *in  = input.data();
    int       *out = output.data();
    const std::size_t stride = N;          // row length in one dimension

    // Parallelise over rows; we use a static schedule with chunk size
    // that matches cache lines to minimise thread over‑head.
    const std::size_t chunk = 64;          // adjust empirically if needed
    #pragma omp parallel for schedule(static, chunk) collapse(1)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t idx      = i * stride;
        const std::size_t idxUp    = (i > 0      ) ? in[idx - stride] : 0;
        const std::size_t idxDown  = (i + 1 < N   ) ? in[idx + stride] : 0;

        for (std::size_t j = 0; j < N; ++j) {
            // Count neighbours that are 1
            int cnt = 0;
            if (i > 0      && idxUp + j          == 1) ++cnt;
            if (i + 1 < N  && idxDown + j        == 1) ++cnt;
            if (j > 0      && in[idx + j - 1]    == 1) ++cnt;
            if (j + 1 < N  && in[idx + j + 1]    == 1) ++cnt;

            out[idx + j] = (cnt == 1) ? 1 : 0;
        }
    }
}
