#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute one iteration of a 5‑point 2‑D Jacobi stencil on `input`.
   Each element of `input` is averaged with its four neighbours and stored
   in `output`.  The value 0 is used when a neighbour lies outside the grid.
   `input` and `output` are N×N grids stored in row‑major order.

   This implementation uses a single OpenMP parallel region with an
   outer‑loop parallelisation.  Loop reordering and pointer arithmetic
   minimise indirect memory accesses, and the compiler is given the
   opportunity for auto‑vectorisation.
*/
inline void jacobi2D(const std::vector<double> &input,
                     std::vector<double> &output,
                     const std::size_t N)
{
    const std::size_t size = N * N;
    if (output.size() < size) output.resize(size);

    const double inv5 = 1.0 / 5.0;

    // Parallelise over rows; each thread processes a whole row so that
    // cache lines are reused efficiently.
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t idx = i * N;               // base index for row i
        const double *up   = (i > 0) ? &input[(i - 1) * N] : nullptr;
        const double *down = (i + 1 < N) ? &input[(i + 1) * N] : nullptr;
        double *out_row = &output[idx];

        for (std::size_t j = 0; j < N; ++j) {
            double sum = input[idx + j];            // centre

            if (up)   sum += up[j];                 // above
            if (down) sum += down[j];               // below

            if (j > 0)   sum += input[idx + j - 1]; // left
            if (j + 1 < N) sum += input[idx + j + 1]; // right

            out_row[j] = sum * inv5;
        }
    }
}
