/*
 * Matrix–vector product: y = A * x
 *
 * - A is an M × N matrix stored in row-major order.
 * - x has N elements, y has M elements.
 * - The routine preserves the exact numerical result of the
 *   reference implementation.
 *
 * Optimisation strategy:
 *  • Parallelise the outer loop with OpenMP (work‑sharing over rows).
 *  • Use pointer arithmetic for minimal overhead.
 *  • Hint the compiler for vectorisation (pragma omp simd).
 *  • Constrain the inner loop to a tight range for the optimiser to
 *    fuse loops efficiently.
 *  • Avoid temporary temporary allocations and unnecessary bounds checks.
 *  • Compile with `-fopenmp -O2` (or higher) for best performance.
 */

inline void gemv(const std::vector<double> &A,
                 const std::vector<double> &x,
                 std::vector<double> &y,
                 std::size_t M, std::size_t N)
{
    // Ensure output vector has sufficient size
    y.resize(M);

    // Parallelise over the rows of A
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        const double* row_ptr = &A[i * N];
        double sum = 0.0;

        // Inner dot product
        #pragma omp simd reduction(+:sum)
        for (std::size_t j = 0; j < N; ++j) {
            sum += row_ptr[j] * x[j];
        }
        y[i] = sum;
    }
}
