#pragma once
#include <vector>
#include <algorithm>

/* Point structure */
struct Point {
    double x, y;
};

/* Fast in‑place convex hull (Andrew's monotone chain). */
inline static double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/*
 * Computes the convex hull of a set of points.
 * The algorithm is exactly the same as the reference implementation,
 * but avoids temporaries and unnecessary copies.
 */
void convexHull(std::vector<Point> const& points, std::vector<Point>& hull) {
    size_t n = points.size();
    if (n < 3) {                           // Degenerate cases
        hull = points;                       // copy, behaviour unchanged
        return;
    }

    /* Sort points lexicographically by x, then y. */
    std::vector<Point> sorted = points;
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    /* Reserve space for both lower and upper hulls (max 2*n). */
    hull.clear();
    hull.reserve(2 * n);

    /* Build lower hull. */
    for (size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(sorted[i]);            // add current point
    }

    /* Build upper hull. */
    size_t lowerSize = hull.size();           // remembered to skip last point
    for (size_t i = n - 1; i > 0; --i) {      // skip first point of sorted
        while (hull.size() > lowerSize &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i - 1]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(sorted[i - 1]);        // add current point
    }

    /* Remove the duplicated start/end point. */
    hull.pop_back();                          // last point equals first
}
