inline double dist2(Point const& a, Point const& b) noexcept
{
    double dx = b.x - a.x;
    double dy = b.y - a.y;
    return dx * dx + dy * dy;
}

inline double hypot2(double dx, double dy) noexcept
{
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   Example:
   input: [{0, 3}, {1, 1}, {2, 2}, {4, 4}, {0, 0}, {1, 2}, {3, 1}, {3, 3}]
   output: 13.4477
*/
inline double convexHullPerimeter(std::vector<Point> const& points) noexcept
{
    if (points.size() < 3)
        return 0.0;

    // copy and sort points
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(), [](Point const& a, Point const& b) noexcept
    {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    const std::size_t n = sorted.size();
    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    auto cross = [](Point const& a, Point const& b, Point const& c) noexcept
    {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    };

    // lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    // upper hull
    for (std::size_t i = n - 1; i > 0; --i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0.0)
            --k;
        hull[k++] = sorted[i - 1];
    }

    hull.resize(k - 1);  // last point is same as the first

    double perimeter = 0.0;
    for (std::size_t i = 0; i < hull.size(); ++i)
    {
        std::size_t j = (i + 1) % hull.size();
        perimeter += hypot2(hull[i].x - hull[j].x, hull[i].y - hull[j].y);
    }

    return perimeter;
}
