    {
        const int v = x[i];
        if (v != 0)
        {
            values.push_back(v);
            pos.push_back(i);
        }
    }

    if (values.size() < 2) return;         // all zeros or one non‑zero

    std::sort(values.begin(), values.end()); // sort the extracted values

    // Write the sorted values back to the original positions.
    const std::size_t m = values.size();
    for (std::size_t i = 0; i < m; ++i)
    {
        x[pos[i]] = values[i];
    }
}
