#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// A highly optimised in‑place radix‑2 FFT implementation, preserving the
// semantics of the original helper (i.e. no extra allocation of the input
// vector, the same data layout, same ordering of the output).
// -----------------------------------------------------------------------------
static void fft_helper(std::vector<std::complex<double>>& data)
{
    // Number of points – must be a power of two.
    const unsigned N   = static_cast<unsigned>(data.size());
    const unsigned log2N= static_cast<unsigned>(std::log2(static_cast<double>(N)));

    // Pre‑compute all twiddle factors for each stage.
    std::vector<std::complex<double>> w(N/2);
    const double theta = -M_PI / static_cast<double>(N);
    for (unsigned i = 0; i < N/2; ++i)
        w[i] = std::polar(1.0, theta * static_cast<double>(i));

    // -------------------------------------------------------------------------
    // Main Cooley‑Tukey radix‑2 butterfly stage.  The loop is split into
    // log2N stages.  We parallelise over the outermost loop (each butterfly
    // in a stage is completely independent of the others in the same stage).
    // -------------------------------------------------------------------------
    for (unsigned stage = 0; stage < log2N; ++stage)
    {
        const unsigned half = 1u << stage;
        const unsigned full  = 1u << (stage+1);
        const unsigned step  = N / full;

        #pragma omp parallel for schedule(static)
        for (unsigned i = 0; i < N; i += full)
        {
            std::complex<double> *p = &data[i];

            for (unsigned j = 0; j < half; ++j)
            {
                const std::complex<double> u = p[j];
                const std::complex<double> v = p[j+half];
                const std::complex<double> t = w[j * step] * v;

                p[j]         = u + t;
                p[j+half]    = u - t;
            }
        }
    }

    // -------------------------------------------------------------------------
    // Bit‑reversal permutation.  This step is embarrassingly parallel as well.
    // -------------------------------------------------------------------------
    const unsigned mask = N - 1;
    #pragma omp parallel for schedule(static)
    for (unsigned i = 0; i < N; ++i)
    {
        unsigned j = 0, k = i;
        for (unsigned b = 0; b < log2N; ++b)
        {
            j = (j << 1) | (k & 1);
            k >>= 1;
        }
        j &= mask;
        if (j > i)
            std::swap(data[i], data[j]);
    }
}

// -----------------------------------------------------------------------------
// Inverse FFT – identical to the original specification.
// -----------------------------------------------------------------------------
static void ifft(std::vector<std::complex<double>>& data)
{
    // Conjugate the data, run forward FFT, conjugate again, and scale.
    std::transform(data.begin(), data.end(), data.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    fft_helper(data);

    std::transform(data.begin(), data.end(), data.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    const double invN = 1.0 / static_cast<double>(data.size());
    std::transform(data.begin(), data.end(), data.begin(),
                   [invN](const std::complex<double>& v){ return v * invN; });
}
