/* Return true if the vector x contains the value `target`. Return false otherwise.
   Examples:

   input: x=[1, 8, 2, 6, 4, 6], target=3
   output: false
   input: x=[1, 8, 2, 6, 4, 6], target=8
   output: true
*/
bool contains(std::vector<int> const& x, int target) {
    // Treat small vectors with the standard one‑pass search
    if (x.size() < 1024) {
        for (auto v : x) {
            if (v == target) return true;
        }
        return false;
    }

    // Parallel search for larger vectors.
    // Use a thread‑local flag to avoid false sharing.
    alignas(64) bool found = false;
    #pragma omp parallel
    {
        bool private_found = false;
        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i) {
            if (x[i] == target) {
                private_found = true;
                break;
            }
        }
        #pragma omp atomic write
        found = found || private_found;
    }
    return found;
}
