    if (books.empty()) return books.size();

    // Reverse loop using pointer arithmetic for minimal overhead
    const Book* ptr = books.data();            // start of vector
    const Book* end = ptr + books.size();      // past-the-end
    const Book* p = end - 1;                   // point to last element

    for (; p >= ptr; --p)
    {
        if (p->pages < 100)
        {
            // Compute index relative to ptr
            return static_cast<size_t>(p - ptr);
        }
    }
