#include <omp.h>

/*
 * Optimised matrix‑matrix multiplication:
 *   C += A × B
 *   A : M × K  (row‑major)
 *   B : K × N  (row‑major)
 *   C : M × N  (row‑major)
 *
 * The implementation uses a cache‑friendly blocking scheme (block size 64),
 * simple loop unrolling of the inner product and OpenMP parallelisation.
 * It preserves the original semantics (increments C with the product).
 */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>&       C,
                 const std::size_t          M,
                 const std::size_t          K,
                 const std::size_t          N)
{
    constexpr std::size_t BLOCK = 64;          // block size tuned for L1/L2 caches

    // Parallelise outermost loop (over blocks of rows of A / C)
    #pragma omp parallel for schedule(static)
    for (std::size_t ii = 0; ii < M; ii += BLOCK) {
        const std::size_t i_max = (ii + BLOCK < M) ? ii + BLOCK : M;

        for (std::size_t kk = 0; kk < K; kk += BLOCK) {
            const std::size_t k_max = (kk + BLOCK < K) ? kk + BLOCK : K;

            for (std::size_t jj = 0; jj < N; jj += BLOCK) {
                const std::size_t j_max = (jj + BLOCK < N) ? jj + BLOCK : N;

                // Main blocked kernel
                for (std::size_t i = ii; i < i_max; ++i) {
                    const double* a_row = &A[i * K];
                    double*       c_row = &C[i * N];

                    for (std::size_t k = kk; k < k_max; ++k) {
                        const double aik = a_row[k];
                        const double* b_row = &B[k * N];
                        std::size_t j = jj;

                        // unroll inner loop – 4×
                        for (; j + 3 < j_max; j += 4) {
                            c_row[j    ] += aik * b_row[j    ];
                            c_row[j + 1] += aik * b_row[j + 1];
                            c_row[j + 2] += aik * b_row[j + 2];
                            c_row[j + 3] += aik * b_row[j + 3];
                        }
                        // spill
                        for (; j < j_max; ++j) {
                            c_row[j] += aik * b_row[j];
                        }
