#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/* Simulate one generation of Game of Life on `input`. Store the results in `output`.
   A cell is 1 if it is alive and 0 if it is dead.
   If a live cell has fewer than 2 live neighbors then it dies.
   If a live cell has 2 or 3 live neighbors then it lives on.
   If a live cell has more than 3 live neighbors then it dies.
   If a cell is dead and has exactly 3 live neighbors then it becomes alive.
   `input` and `output` are NxN grids stored in row-major.
*/
inline void gameOfLife(const std::vector<int> &input,
                      std::vector<int> &output,
                      std::size_t N)
{
    // Ensure output has the same size as input
    if (output.size() != input.size()) output.resize(input.size());

    const int *in  = input.data();
    int       *out = output.data();
    const std::size_t stride = N;          // number of columns per row

    // Parallelise over rows and columns (nested loops collapsed to one)
    #pragma omp parallel for schedule(static) collapse(2)
    for (std::size_t i = 0; i < N; ++i)
    {
        // Pointers to the start of the previous and next rows
        const int *row_above = (i > 0) ? in + (i - 1) * stride : nullptr;
        const int *row_below = (i + 1 < N) ?  in + (i + 1) * stride : nullptr;
        const int *row_curr  = in + i * stride;

        for (std::size_t j = 0; j < N; ++j)
        {
            // Use a local variable for speed; compiler will keep it in register.
            int sum = 0;

            // West / East (same row)
            if (j > 0)     sum += row_curr[j - 1];
            if (j + 1 < N) sum += row_curr[j + 1];

            // North / South (adjacent rows)
            if (row_above) sum += row_above[j];
            if (row_below) sum += row_below[j];

            // Diagonals
            if (row_above && j > 0)     sum += row_above[j - 1];
            if (row_above && j + 1 < N) sum += row_above[j + 1];
            if (row_below && j > 0)     sum += row_below[j - 1];
            if (row_below && j + 1 < N) sum += row_below[j + 1];

            const int cur = row_curr[j];
            int next = 0;
            if (cur == 1) {
                if (sum == 2 || sum == 3) next = 1;
            } else {
                if (sum == 3) next = 1;
            }
            out[i * stride + j] = next;
        }
    }
}
