/* Compute the rank of each element in `x` and write it into `ranks_`.
   Ranks are stable with respect to equal elements (same order as in `x`). */
inline void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    const std::size_t n = x.size();

    /* 1. Prepare permutation of indices */
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    /* 2. Stable sort the indices according to the corresponding values in x */
    std::stable_sort(indices.begin(), indices.end(),
                     [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    /* 3. Write the rank of each original element */
#ifdef _OPENMP
#pragma omp parallel for schedule(static)
#endif
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
