#pragma once
#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

// Edge kernel: 3x3 Sobel-like operator
constexpr int edgeKernel[3][3] = {
    { -1, -1, -1 },
    { -1,  8, -1 },
    { -1, -1, -1 }
};

// Convolve `imageIn` with the edge kernel and store the result in `imageOut`.
// `imageIn` and `imageOut` are N×N grayscale images in row‑major order.
// The function is fully parallelised with OpenMP and uses small local
// buffers to reduce runtime overhead.
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           const size_t N)
{
    // Early return for empty images
    if (N == 0 || imageIn.empty() || imageOut.empty()) return;

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t iN = i * N;       // start index of current row
        for (size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // Manually unroll the 3x3 neighbourhood
            // Top row
            if (i > 0)
            {
                const size_t idx0 = (i - 1) * N; // row above
                const int* rowPtr = &imageIn[idx0];

                if (j > 0) sum += rowPtr[j - 1] * edgeKernel[0][0];
                sum        += rowPtr[j]       * edgeKernel[0][1];
                if (j + 1 < N) sum += rowPtr[j + 1] * edgeKernel[0][2];
            }
            else
            {
                // Out of bounds → kernel value * 0 (skip)
                sum += 0; // top-left
                sum += 0; // top
                sum += 0; // top-right
            }

            // Middle row
            {
                const int* rowPtr = &imageIn[iN];
                if (j > 0) sum += rowPtr[j - 1] * edgeKernel[1][0];
                sum        += rowPtr[j]       * edgeKernel[1][1];
                if (j + 1 < N) sum += rowPtr[j + 1] * edgeKernel[1][2];
            }

            // Bottom row
            if (i + 1 < N)
            {
                const size_t idx1 = (i + 1) * N; // row below
                const int* rowPtr = &imageIn[idx1];

                if (j > 0) sum += rowPtr[j - 1] * edgeKernel[2][0];
                sum        += rowPtr[j]       * edgeKernel[2][1];
                if (j + 1 < N) sum += rowPtr[j + 1] * edgeKernel[2][2];
            }
            else
            {
                sum += 0; // bottom-left
                sum += 0; // bottom
                sum += 0; // bottom-right
            }

            // Clip to [0,255]
            if (sum < 0)
                imageOut[iN + j] = 0;
            else if (sum > 255)
                imageOut[iN + j] = 255;
            else
                imageOut[iN + j] = sum;
        }
    }
}
