```cpp
#pragma once
#include <vector>
#include <cstddef>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   Examples:
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=7
   output: true
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=1
   output: false
*/
bool xorContains(std::vector<int> const& x, std::vector<int> const& y, int val) {
    bool foundInX = false, foundInY = false;

    // Scan first vector
    for (const int* p = x.data(); p != x.data() + x.size(); ++p) {
        if (*p == val) {
            foundInX = true;
            break;
        }
    }

    // Scan second vector
    for (const int* p = y.data(); p != y.data() + y.size(); ++p) {
        if (*p == val) {
            foundInY = true;
            break;
        }
    }

    return foundInX ^ foundInY;
}
