```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

static inline std::complex<double> exp_minus_j_pi_over_n(unsigned int n)
{
    const double PI = 3.14159265358979323846264338328;
    double ang = -PI / static_cast<double>(n);
    return std::complex<double>(std::cos(ang), std::sin(ang));
}

/* Pre‑compute twiddle factors for a radix‑2 FFT of size N.
   For each stage `s` (1‑based), stage_size = 2^s
   and we need twiddle factors for k = 0 .. stage_size/2-1. */
static inline void precompute_twiddles(unsigned int N,
                                       std::vector<std::vector<std::complex<double>>> &twiddles)
{
    unsigned int stages = 0, tmp = N;
    while (tmp >>= 1) ++stages;
    twiddles.resize(stages);
    for (unsigned int s = 0; s < stages; ++s) {
        unsigned int half = 1u << s;
        unsigned int m    = half << 1;
        twiddles[s].resize(half);
        std::complex<double> w = exp_minus_j_pi_over_n(m);
        std::complex<double> w_pow = 1.0;
        for (unsigned int k = 0; k < half; ++k) {
            twiddles[s][k] = w_pow;
            w_pow *= w;
        }
    }
}

/* Pre‑compute bit‑reversal table for a power‑of‑two N. */
static inline void precompute_bitrev(unsigned int N, std::vector<unsigned int> &bitrev)
{
    unsigned int nbits = 0, tmp = N;
    while (tmp >>= 1) ++nbits;
    bitrev.resize(N);
    for (unsigned int i = 0; i < N; ++i) {
        unsigned int rev = 0, x = i;
        for (unsigned int b = 0; b < nbits; ++b, x >>= 1)
            rev = (rev << 1) | (x & 1u);
        bitrev[i] = rev;
    }
}

/* In‑place radix‑2 FFT with conjugate and bit reversal */
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const unsigned int N = (unsigned int)x.size();
    if (N == 0) return;

    /* ---- phase 1: iterative Cooley–Tukey ---- */
    std::vector<std::vector<std::complex<double>>> twiddles;
    precompute_twiddles(N, twiddles);

    unsigned int stages = (unsigned int)twiddles.size();
    for (unsigned int s = 0; s < stages; ++s) {
        unsigned int half = 1u << s;          // butterflies per group
        unsigned int m    = half << 1;         // size of current group
        const std::vector<std::complex<double>>& W = twiddles[s];

        /* Each `l` runs on a disjoint set of `half` pairs. */
#pragma omp parallel for schedule(static)
        for (unsigned int l = 0; l < half; ++l) {
            std::complex<double> w = W[l];
            for (unsigned int a = l; a < N; a += m) {
                unsigned int b = a + half;
                std::complex<double> t = x[a] - x[b];
                x[a] += x[b];
                x[b] = t * w;
            }
        }
    }

    /* ---- phase 2: bit‐reversal ---- */
    std::vector<unsigned int> bitrev;
    precompute_bitrev(N, bitrev);
    for (unsigned int i = 0; i < N; ++i) {
        unsigned int j = bitrev[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    /* ---- phase 3: conjugate ---- */
#pragma omp parallel for schedule(static)
    for (long long i = 0; i < static_cast<long long>(N); ++i)
        x[i] = std::conj(x[i]);
}
