```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/* Compute the radix‑2 Cooley–Tukey FFT.
   Behaviour matches the original implementation.
   N must be a power of two. */
void fft(const std::vector<std::complex<double>> &x,
         std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    if (N == 0) {
        output.clear();
        return;
    }

    output = x;                         // copy input

    /* ---- bit‑reversal permutation ----------------------------------- */
    const std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = ((j & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((j & 0x5555555555555555ULL) << 1);
        j = ((j & 0xccccccccccccccccULL) >> 2) | ((j & 0x3333333333333333ULL) << 2);
        j = ((j & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((j & 0x0f0f0f0f0f0f0f0fULL) << 4);
        j = ((j & 0xff00ff00ff00ff00ULL) >> 8) | ((j & 0x00ff00ff00ff00ffULL) << 8);
        j = ((j & 0xffff0000ffff0000ULL) >>16) | ((j & 0x0000ffff0000ffffULL) <<16);
        j >>= (64 - logN);
        if (j > i) std::swap(output[i], output[j]);
    }

    /* ---- iterative radix‑2 FFT -------------------------------------- */
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m  = 1ull << s;          // block size
        const std::size_t m2 = m >> 1;             // half block
        const double theta = -2.0 * M_PI / static_cast<double>(m);
        const std::complex<double> w_m(std::cos(theta), std::sin(theta));

        /* parallel over independent blocks */
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < m2; ++j) {
                const std::size_t evenIdx = k + j;
                const std::size_t oddIdx  = evenIdx + m2;

                const std::complex<double> t = w * output[oddIdx];
                const std::complex<double> u = output[evenIdx];

                output[evenIdx] = u + t;
                output[oddIdx]  = u - t;

                w *= w_m;
            }
        }
    }
}
