01_dense_la_solve:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              std::size_t N)
{
    // Create a writable copy of the inputs
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    double* a = A_copy.data();
    double* bb = b_copy.data();

    // Gaussian elimination with parallel elimination of rows
    for (std::size_t i = 0; i < N - 1; ++i) {
        const double pivot = a[i * N + i];
        if (pivot == 0.0) return;    // singular matrix – same behavior as original

        const double invPivot = 1.0 / pivot;

        // Eliminate lower rows – this part can be parallelized
#pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            const double factor = a[j * N + i] * invPivot;
            double* row_j    = a + j * N;
            const double* row_i = a + i * N;
            for (std::size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            bb[j] -= factor * bb[i];
        }
    }

    // Back substitution – performs one sum per row, the inner sum is parallelized
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* row_i = a + i * N;
#pragma omp parallel for reduction(+:sum) schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += row_i[j] * x[j];
        }
        x[i] = (bb[i] - sum) / a[i * N + i];
    }
}
