```cpp
#pragma once
#include <vector>
#include <cmath>
#include <cstddef>
#include <limits>
#include <omp.h>

/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x) {
    if (x.empty()) return 0;  // undefined behaviour for empty vector; mimic original code

    int nthreads = omp_get_max_threads();
    std::vector<double> thread_min(nthreads, std::numeric_limits<double>::infinity());
    std::vector<size_t> thread_idx(nthreads, 0);

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i) {
        double diff = std::abs(x[i] - M_PI);
        int t = omp_get_thread_num();
        if (diff < thread_min[t]) {
            thread_min[t] = diff;
            thread_idx[t] = i;
        }
    }

    // Find global minimum among thread results
    double global_min = std::numeric_limits<double>::infinity();
    size_t best_index = 0;
    for (int t = 0; t < nthreads; ++t) {
        if (thread_min[t] < global_min) {
            global_min = thread_min[t];
            best_index = thread_idx[t];
        }
    }
    return best_index;
}
